import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    # {This algorithm uses a weighted scoring system considering distance, time windows, penalty, and balance across trucks, aiming to minimize makespan.}

    def euclidean_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    best_score = float('inf')
    best_node = None
    num_trucks = len(all_truck_pos)

    for index, customer in enumerate(unvisited_customers):
        travel_time = euclidean_distance(cur_truck_pos, customer) / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[index]
        wait_time = max(0, start_window - arrival_time)

        # Penalty for waiting or missing the time window
        if arrival_time > end_window:
            penalty = float('inf')
        else:
            penalty = wait_time * 10  # Large penalty for waiting

        # Calculate distance to depot for completing the tour
        distance_to_depot = euclidean_distance(customer, depot_pos)

        # Compute total score for customer selection
        score = travel_time + wait_time + penalty + (distance_to_depot / num_trucks)

        if score < best_score:
            best_score = score
            best_node = index

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    min_cost = float('inf')
    best_node = None

    for idx, (customer_pos, time_window) in enumerate(zip(unvisited_customers, time_windows)):
        dist_to_customer = np.linalg.norm(cur_truck_pos - customer_pos)
        arrival_time = current_time + dist_to_customer / truck_speed

        if time_window[0] <= arrival_time <= time_window[1]:
            penalty = 0
        elif arrival_time < time_window[0]:
            penalty = time_window[0] - arrival_time
        else:
            penalty = float('inf')

        if penalty < float('inf'):
            dist_to_depot = np.linalg.norm(customer_pos - depot_pos)
            total_dist = dist_to_customer + dist_to_depot

            cost = penalty + total_dist
            if cost < min_cost:
                min_cost = cost
                best_node = idx

    return best_node
